  if (data.length <= 1) {
    return jsonResponse({ success: true, data: [] });
  }

  const headers = data[0].map(h => String(h).trim()); // clean headers
  const rows = [];

  for (let i = 1; i < data.length; i++) {
    const row = data[i];
    const obj = {};
    for (let j = 0; j < headers.length; j++) {
      let val = row[j];
      // Handle errors & non-JSON-safe values
      if (val instanceof Error || (typeof val === 'string' && val.match(/#DIV\/0!|#VALUE!|#N\/A/i))) {
        val = '';
      } else if (typeof val === 'number' && !isFinite(val)) {
        val = 0; // NaN/Infinity → 0
      }
      obj[headers[j]] = val ?? '';
    }
    rows.push(obj);
  }

  // If too many rows, consider pagination later — for now log count
  Logger.log(`getAllRows for ${sheetName}: ${rows.length} rows processed`);
  
  return jsonResponse({ success: true, data: rows });
