      sheet.getRange(truckRow, 8).setValue(Number(data.TransporterBillingCbm) || 0);  // H
      sheet.getRange(truckRow, 9).setValue(Number(data.DredgerBillingCbm)     || 0);  // I
      sheet.getRange(truckRow,10).setValue(data.TruckName || 'Unnamed');
