// Simple helper if needed
function generateReference() {
  const now = new Date();
  const yyyymmdd = Utilities.formatDate(now, "GMT", "yyyyMMdd");
  const rand = Math.random().toString(36).substring(2, 8).toUpperCase();
  return `TRIP-${yyyymmdd}-${rand}`;
}

// ────────────────────────────────────────────────
