// ────────────────────────────────────────────────
function updateTrip(ss, data) {
  const sheet = ss.getSheetByName('Trips');
  
  // Use Reference as the stable key (safer than rowNumber)
  const reference = (data.Reference || data.reference || "").toString().trim();
  
  if (!reference) {
    return jsonResponse({ success: false, error: "Missing Reference for update" });
  }

  const values = sheet.getDataRange().getValues();
  let rowToDelete = -1;

  // Search for row by Reference (column O = index 14, assuming 0-based)
  for (let i = 1; i < values.length; i++) {  // start from row 2
    if (String(values[i][14]).trim() === reference) {
      rowToDelete = i + 1;  // 1-based row number
      break;
    }
  }

  if (rowToDelete > 1) {
    sheet.deleteRow(rowToDelete);
    Logger.log(`Updated trip: deleted old row ${rowToDelete} with ref ${reference}`);
  } else {
    Logger.log(`Update failed: Reference not found - ${reference}`);
    return jsonResponse({ success: false, error: "Reference not found: " + reference });
  }

  // Append the updated data (same logic as saveTrip)
  return saveTrip(ss, data);
}

