function handleRequest(e) {
  // Handle CORS preflight (OPTIONS) early
  if (e.parameter && e.parameter.action === 'OPTIONS' || 
      (!e.postData && (!e.parameter || Object.keys(e.parameter).length === 0))) {
    return doOptions();
  }

  let action = null;
  let data = {};

  try {
    const ss = SpreadsheetApp.openById(SHEET_ID);

    // 1. Priority: form-urlencoded POST or GET (bypasses CORS preflight)
    if (e.parameter && Object.keys(e.parameter).length > 0) {
      action = e.parameter.action;
      data = e.parameter;  // all params become data (TripCBM=12.5, etc.)
    } 
    // 2. Fallback: old JSON POST
    else if (e.postData && e.postData.contents) {
      const parsed = JSON.parse(e.postData.contents);
      action = parsed.action;
      data = parsed.data || parsed;
    }

    if (!action) {
      return jsonResponse({ success: false, error: 'No action provided' });
    }

    // ────────────────────────────────────────────────
    // Main action routing
    // ────────────────────────────────────────────────
    if (action === 'saveDredger')     return saveDredger(ss, data);
    if (action === 'saveTransporter') return saveTransporter(ss, data);
    if (action === 'saveTrip')        return saveTrip(ss, data);
    if (action === 'updateTrip')      return updateTrip(ss, data);
    if (action === 'savePayment')     return savePayment(ss, data);

    if (action === 'deleteDredger')   return deleteRow(ss, 'Dredgers',    'Code', data.code || data.Code);
    if (action === 'deleteTransporter') return deleteRow(ss, 'Transporters','Code', data.code || data.Code);
    if (action === 'deleteTrip')      return deleteTrip(ss, data);
    if (action === 'deletePayment')   return deletePayment(ss, data);

    if (action === 'addTruck')        return saveTransporter(ss, data);
    if (action === 'deleteTruck')     return deleteTruck(ss, data);

    if (action === 'getDredgers')     return getAllRows(ss, 'Dredgers');
    if (action === 'getTransporters') return getAllRows(ss, 'Transporters');
    if (action === 'getTrips')        return getAllRows(ss, 'Trips');
    if (action === 'getPayments')     return getAllRows(ss, 'Payments');

    return jsonResponse({ success: false, error: 'Unknown action: ' + action });
  } catch (err) {
    return jsonResponse({ success: false, error: err.message + ' → ' + err.stack });
  }
}
