// ────────────────────────────────────────────────
function saveTrip(ss, data) {

  // Log incoming data for debugging (check Execution log in GAS)
  Logger.log('saveTrip received: ' + JSON.stringify(data));

  const row = [
    data.Date                  || '',
    data.DredgerCode           || '',
    data.TransporterCode       || '',
    data.PlateNumber           || '',
    Number(data.Trips)         || 0,
    Number(data.DredgerRate)   || 0,
    Number(data.TransporterRate) || 0,
    data.DumpingLocation       || '',
    data.Notes                 || '',
    Number(data.DredgerAmount) || 0,
    Number(data.TransporterAmount) || 0,
    Number(data.TripCBM)       || 0,           // ← force 0 instead of ''
    Number(data.ActualLoadedCbm) || 0,         // ← force 0
    Number(data.TotalTripsVolume) || 0,        // ← force 0
    data.Reference             || generateReference()
  ];
  sheet.appendRow(row);
  
  Logger.log('Trip appended: ' + JSON.stringify(row));

  return jsonResponse({ success: true, message: 'Trip saved' });
}

// Simple helper if needed
function generateReference() {
  const now = new Date();
  const yyyymmdd = Utilities.formatDate(now, "GMT", "yyyyMMdd");
  const rand = Math.random().toString(36).substring(2, 8).toUpperCase();
  return `TRIP-${yyyymmdd}-${rand}`;
}

// ────────────────────────────────────────────────
//  TRIP - UPDATE (delete old + append new)
// ────────────────────────────────────────────────
// ────────────────────────────────────────────────
//  TRIP - UPDATE (find by Reference → delete old → append new)
// ────────────────────────────────────────────────
function updateTrip(ss, data) {
  const sheet = ss.getSheetByName('Trips');
  
  // Use Reference as the stable key (safer than rowNumber)
  const reference = (data.Reference || data.reference || "").toString().trim();
  
  if (!reference) {
    return jsonResponse({ success: false, error: "Missing Reference for update" });
  }

  const values = sheet.getDataRange().getValues();
  let rowToDelete = -1;

  // Search for row by Reference (column O = index 14, assuming 0-based)
  for (let i = 1; i < values.length; i++) {  // start from row 2
    if (String(values[i][14]).trim() === reference) {
      rowToDelete = i + 1;  // 1-based row number
      break;
    }
  }

  if (rowToDelete > 1) {
    sheet.deleteRow(rowToDelete);
    Logger.log(`Updated trip: deleted old row ${rowToDelete} with ref ${reference}`);
  } else {
    Logger.log(`Update failed: Reference not found - ${reference}`);
    return jsonResponse({ success: false, error: "Reference not found: " + reference });
  }

  // Append the updated data (same logic as saveTrip)
  return saveTrip(ss, data);
}

// ────────────────────────────────────────────────
//  DELETE TRIP by row number
// ────────────────────────────────────────────────
function deleteTrip(ss, data) {
  const sheet = ss.getSheetByName('Trips');
  const row   = Number(data.rowNumber || data.Row || data.row || 0);

  if (row > 1) {
    sheet.deleteRow(row);
    return jsonResponse({ success: true });
  }

  return jsonResponse({ success: false, error: 'Invalid row number' });
}

